  def test_login(self):
    self.driver.get("https://memoretos.atoligue.uber.space/registro/")
    self.driver.set_window_size(1152, 686)
    self.driver.find_element(By.ID, "reg-user").click()
    self.driver.find_element(By.CSS_SELECTOR, "body").click()
    self.driver.find_element(By.CSS_SELECTOR, ".btn-entrar").click()
    self.driver.find_element(By.ID, "reg-user").send_keys("Pedro Gutierrez")
