    self.driver.find_element(By.ID, "reg-mail").send_keys("a0123456@tec.mx")
    self.driver.find_element(By.CSS_SELECTOR, ".btn-entrar").click()
    self.driver.find_element(By.ID, "reg-pass").send_keys("12345678")
    self.driver.find_element(By.ID, "reg-rol").click()
    dropdown = self.driver.find_element(By.ID, "reg-rol")
    dropdown.find_element(By.XPATH, "//option[. = 'Maestro']").click()
    self.driver.find_element(By.CSS_SELECTOR, ".btn-entrar").click()
    assert self.driver.switch_to.alert.text == "¡Registro exitoso! Ya puedes iniciar sesión."
    self.driver.find_element(By.ID, "user").click()
    self.driver.find_element(By.ID, "user").send_keys("Pedro Gutierrez")
    self.driver.find_element(By.ID, "pass").click()
    self.driver.find_element(By.ID, "pass").send_keys("12345678")
    self.driver.find_element(By.CSS_SELECTOR, ".btn-entrar").click()
    assert self.driver.switch_to.alert.text == "¡Bienvenido, profesor!"
    self.driver.find_element(By.CSS_SELECTOR, ".class-btn:nth-child(2)").click()
    self.driver.find_element(By.CSS_SELECTOR, ".class-btn:nth-child(3)").click()
  
